// src/components/Sidebar.js
import React from 'react';

const Sidebar = () => {
    return (
        <aside style={styles.sidebar}>
            <ul style={styles.ul}>
                <li style={styles.li}>Ana Sayfa</li>
                <li style={styles.li}>Profil</li>
                <li style={styles.li}>Ayarlar</li>
                <li style={styles.li}>Çıkış</li>
            </ul>
        </aside>
    );
};

const styles = {
    sidebar: {
        width: '200px',
        height: '100vh',
        background: '#34495e',
        color: '#ecf0f1',
        paddingTop: '20px',
    },
    ul: {
        listStyle: 'none',
        padding: 0,
    },
    li: {
        padding: '10px 20px',
        cursor: 'pointer',
    },
};

export default Sidebar;
